109	/// [`Context`] impl used by [`SingleThreadRuntime`]: pushes onto
110	/// the runtime's shared queue.
111	struct SingleCtx<'a> {
112	    queue: &'a mut VecDeque<(u32, Message)>,
113	}
114	
115	impl Context for SingleCtx<'_> {
116	    /// Push `(dst_id, msg)` onto the shared dispatch queue.
117	    fn send(&mut self, dst_id: u32, msg: Message) {
118	        self.queue.push_back((dst_id, msg));
119	    }
120	}
