211	// --- MultiThreadRuntime -------------------------------------------------
212	
213	/// Multi-threaded runtime: one thread per actor, messages flow
214	/// over per-actor [`std::sync::mpsc`] channels. Each actor thread
215	/// owns a [`TProbe`] recording per-`handle_message` latency at
216	/// `inner=1`; probes are returned to the caller when threads join.
217	///
218	/// Unlike [`SingleThreadRuntime`], actors are registered as
219	/// factory closures — construction runs inside the actor's own
220	/// thread, so users don't need `Send` on the trait itself, only on
221	/// the actor implementor and its factory.
222	///
223	/// Shutdown is in-band: an internal `Signal::Shutdown` value
224	/// travels the same channel that carries user messages, so the
225	/// actor's `recv()` loop exits cleanly after the measurement
226	/// window elapses. A `Signal::ClearProbe` is used at the warmup →
227	/// measurement boundary so only steady-state data reaches the
228	/// report.
229	///
230	/// Ping-pong style workloads hold one message in flight between
231	/// two actors; `inner > 1` batching would leave every probe scope
232	/// partial (queue empties mid-batch) so this runtime hardcodes
233	/// `inner = 1`. If we later add a Goal with higher queue depth
234	/// we'll revisit.
235	pub struct MultiThreadRuntime {
236	    factories: Vec<ActorFactory>,
237	    probe_name_prefix: String,
238	    pending_seeds: Vec<(u32, Message)>,
239	}
240	
241	/// Boxed factory: produces a `Box<dyn Actor + Send>` once, called
242	/// inside the actor's dedicated thread. `Send` on the outer
243	/// closure is required so it can be moved into `thread::spawn`.
244	type ActorFactory = Box<dyn FnOnce() -> Box<dyn Actor + Send> + Send>;
245	
246	/// Internal channel payload. User sends become [`Signal::User`];
247	/// [`Signal::ClearProbe`] and [`Signal::Shutdown`] are injected by
248	/// the runtime to drive phase transitions and exit.
249	enum Signal {
250	    User(Message),
251	    ClearProbe,
252	    Shutdown,
253	}
254	
255	impl MultiThreadRuntime {
256	    /// Create an empty runtime. `probe_name_prefix` is combined
257	    /// with the actor id to form each per-thread probe's name
258	    /// (e.g. `"goal2.dispatch.actor0"`).
259	    pub fn new(probe_name_prefix: &str) -> Self {
260	        Self {
261	            factories: Vec::new(),
262	            probe_name_prefix: probe_name_prefix.to_string(),
263	            pending_seeds: Vec::new(),
264	        }
265	    }
266	
267	    /// Register an actor factory; returns the assigned id
268	    /// (0-indexed). `factory` is called inside the spawned thread
269	    /// that will drive this actor, so the actor type itself does
270	    /// not need to be `Send` before the call — only the factory.
271	    pub fn add_actor<F, A>(&mut self, factory: F) -> u32
272	    where
273	        F: FnOnce() -> A + Send + 'static,
274	        A: Actor + Send + 'static,
275	    {
276	        let id = self.factories.len() as u32;
277	        self.factories.push(Box::new(move || {
278	            Box::new(factory()) as Box<dyn Actor + Send>
279	        }));
280	        id
281	    }
282	
283	    /// Enqueue an initial message for `dst_id`. Delivered after
284	    /// all threads spawn and before warmup begins.
285	    pub fn seed(&mut self, dst_id: u32, msg: Message) {
286	        self.pending_seeds.push((dst_id, msg));
287	    }
288	
289	    /// Spawn one thread per registered actor, run the warmup
290	    /// phase, clear all probes, run the measurement phase, shut
291	    /// down and join every thread. Returns each actor's
292	    /// `(messages_handled, probe)` pair in id order. Consumes the
293	    /// runtime's registered factories and pending seeds.
294	    ///
295	    /// `pin_cores` is a list of logical CPUs to pin actor threads
296	    /// to; actor `i` pins to `pin_cores[i % pin_cores.len()]`.
297	    /// An empty slice leaves all actor threads unpinned.
298	    pub fn run(
299	        &mut self,
300	        warmup: Duration,
301	        measurement: Duration,
302	        pin_cores: &[usize],
303	    ) -> Vec<(u64, TProbe)> {
304	        let factories = std::mem::take(&mut self.factories);
305	        let seeds = std::mem::take(&mut self.pending_seeds);
306	        let n = factories.len();
307	
308	        // Per-actor channels.
309	        let mut senders: Vec<Sender<Signal>> = Vec::with_capacity(n);
310	        let mut receivers: Vec<Option<Receiver<Signal>>> = Vec::with_capacity(n);
311	        for _ in 0..n {
312	            let (tx, rx) = mpsc::channel();
313	            senders.push(tx);
314	            receivers.push(Some(rx));
315	        }
316	
317	        // Spawn one thread per actor.
318	        let mut handles: Vec<JoinHandle<(u64, TProbe)>> = Vec::with_capacity(n);
319	        for (id, factory) in factories.into_iter().enumerate() {
320	            #[allow(clippy::unwrap_used)]
321	            // OK: receivers[id] was Some(...) since we pushed one per actor above.
322	            let rx = receivers[id].take().unwrap();
323	            let peers: Vec<Sender<Signal>> = senders.to_vec();
324	            let probe_name = format!("{}.actor{}", self.probe_name_prefix, id);
325	            let pin_target = if pin_cores.is_empty() {
326	                None
327	            } else {
328	                Some(pin_cores[id % pin_cores.len()])
329	            };
330	            let h = thread::Builder::new()
331	                .name(format!("actor-{id}"))
332	                .spawn(move || {
333	                    tprobe::pin::pin_current(pin_target);
334	                    let actor = factory();
335	                    actor_loop(actor, rx, peers, probe_name)
336	                })
337	                .expect("failed to spawn actor thread");
338	            handles.push(h);
339	        }
340	
341	        // Seed initial messages.
342	        for (dst, msg) in seeds {
343	            #[allow(clippy::unwrap_used)]
344	            // OK: receivers are alive (threads just spawned); a send failure would
345	            //   indicate an immediate thread panic on startup which the subsequent
346	            //   join will surface with a clearer message.
347	            senders[dst as usize].send(Signal::User(msg)).unwrap();
348	        }
349	
350	        // Phase 1: warmup.
351	        thread::sleep(warmup);
352	
353	        // Clear every probe at the phase boundary.
354	        for tx in &senders {
355	            let _ = tx.send(Signal::ClearProbe);
356	        }
357	
358	        // Phase 2: measurement.
359	        thread::sleep(measurement);
360	
361	        // Phase 3: shutdown.
362	        for tx in &senders {
363	            let _ = tx.send(Signal::Shutdown);
364	        }
365	        // Drop the main-thread copies so no dangling senders keep
366	        // channels open past thread exit.
367	        drop(senders);
368	
369	        // Join and collect (count, probe) in id order.
370	        let mut results = Vec::with_capacity(n);
371	        for h in handles {
372	            results.push(h.join().expect("actor thread panicked"));
373	        }
374	        results
375	    }
376	}
377	
378	/// [`Context`] impl used inside each actor thread: dispatches
379	/// user sends over the shared peer senders.
380	struct MultiCtx<'a> {
381	    senders: &'a [Sender<Signal>],
382	}
383	
384	impl Context for MultiCtx<'_> {
385	    /// Send `msg` to `dst_id`'s mpsc channel. A closed channel
386	    /// (peer has already exited) is silently ignored — matches
387	    /// the shutdown semantics.
388	    fn send(&mut self, dst_id: u32, msg: Message) {
389	        let _ = self.senders[dst_id as usize].send(Signal::User(msg));
390	    }
391	}
392	
393	/// Actor thread's main loop. Creates a [`TProbe`] named
394	/// `probe_name`, blocks on `rx.recv()`, and for each
395	/// `Signal::User` message probes a scope, dispatches
396	/// `handle_message`, and increments the count.
397	/// `Signal::ClearProbe` resets the probe and count;
398	/// `Signal::Shutdown` (or a closed channel) exits the loop and
399	/// returns `(count, probe)`.
400	fn actor_loop(
401	    mut actor: Box<dyn Actor + Send>,
402	    rx: Receiver<Signal>,
403	    peers: Vec<Sender<Signal>>,
404	    probe_name: String,
405	) -> (u64, TProbe) {
406	    let mut probe = TProbe::new(&probe_name);
407	    let mut count: u64 = 0;
408	    loop {
409	        match rx.recv() {
410	            Ok(Signal::User(msg)) => {
411	                let id = probe.start(0);
412	                let mut ctx = MultiCtx { senders: &peers };
413	                actor.handle_message(&mut ctx, msg);
414	                probe.end(id);
415	                count += 1;
416	            }
417	            Ok(Signal::ClearProbe) => {
418	                probe.clear();
419	                count = 0;
420	            }
421	            Ok(Signal::Shutdown) | Err(_) => break,
422	        }
423	    }
424	    (count, probe)
425	}
426	
427	#[cfg(test)]
428	mod mt_tests {
429	    use super::*;
430	
431	    /// Unbounded ping-pong actor used for multi-thread tests.
432	    struct ThreadPingPong {
433	        peer: u32,
434	    }
435	
436	    impl Actor for ThreadPingPong {
437	        fn handle_message(&mut self, ctx: &mut dyn Context, _: Message) {
438	            ctx.send(self.peer, Message);
439	        }
440	    }
441	
442	    #[test]
443	    fn multi_thread_runs_measures_and_shuts_down_cleanly() {
444	        let mut rt = MultiThreadRuntime::new("test");
445	        rt.add_actor(|| ThreadPingPong { peer: 1 });
446	        rt.add_actor(|| ThreadPingPong { peer: 0 });
447	        rt.seed(0, Message);
448	        // 50ms each phase — leaves plenty of slack even on
449	        // heavily loaded CI, while still under 0.2s total.
450	        let results = rt.run(Duration::from_millis(50), Duration::from_millis(50), &[]);
451	        assert_eq!(results.len(), 2);
452	        // Ping-pong is symmetric: both actors should have handled
453	        // messages during the measurement window.
454	        let total: u64 = results.iter().map(|(c, _)| *c).sum();
455	        assert!(
456	            total > 0,
457	            "expected some messages processed during measurement, got {total}"
458	        );
459	    }
460	}
